import type { ReservationForm } from "./reservationSchema";

function formatDate(iso: string): string {
  const d = new Date(iso + "T12:00:00");
  return d.toLocaleDateString("es-CO", {
    weekday: "short",
    day: "numeric",
    month: "long",
    year: "numeric",
  });
}

function sectionLabel(value: string): string {
  const map: Record<string, string> = {
    "casa-completa": "Casa completa",
    "seccion-1": "Sección 1 — Casa principal",
    "seccion-2": "Sección 2 — Anexo privado",
  };
  return map[value] ?? value;
}

export function buildReservationMessage(data: ReservationForm): string {
  const lines = [
    `🏡 *Nueva reserva — ${SITE.name}*`,
    "",
    "👤 *Datos del huésped*",
    `• Nombre: ${data.nombre}`,
    `• Teléfono: ${data.telefono}`,
    `• Correo: ${data.email}`,
    "",
    "📅 *Fechas*",
    `• Check-in: ${formatDate(data.checkIn)}`,
    `• Check-out: ${formatDate(data.checkOut)}`,
    `• Noches: ${data.noches}`,
    "",
    "🛏️ *Estadía*",
    `• Sección: ${sectionLabel(data.seccion)}`,
    `• Adultos: ${data.adultos}`,
    `• Niños: ${data.ninos}`,
    `• Total huéspedes: ${data.adultos + data.ninos}`,
  ];

  if (data.mensaje?.trim()) {
    lines.push("", "💬 *Mensaje*", data.mensaje.trim());
  }

  lines.push(
    "",
    "—",
    "Enviado desde casacastrocarrero.com",
    "Por favor confirmar disponibilidad y precio. ¡Gracias!"
  );

  return lines.join("\n");
}

export function openWhatsApp(message: string): void {
  const url = `https://wa.me/${SITE.phoneRaw}?text=${encodeURIComponent(message)}`;
  window.open(url, "_blank", "noopener,noreferrer");
}

export function openWhatsAppInquiry(text?: string): void {
  const defaultText =
    text ??
    "Hola Casa Castro Carrero, tengo una consulta sobre disponibilidad.";
  openWhatsApp(defaultText);
}

import { z } from "zod";

function nightsBetween(checkIn: string, checkOut: string): number {
  const start = new Date(checkIn + "T12:00:00");
  const end = new Date(checkOut + "T12:00:00");
  const diff = (end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24);
  return Math.max(0, Math.round(diff));
}

export const reservationSchema = z
  .object({
    nombre: z
      .string()
      .min(3, "Ingresa tu nombre completo (mínimo 3 caracteres)"),
    telefono: z
      .string()
      .min(7, "Ingresa un teléfono válido")
      .regex(/^[\d\s+\-()]+$/, "Solo números y símbolos de teléfono"),
    email: z.string().email("Correo electrónico no válido"),
    checkIn: z.string().min(1, "Selecciona la fecha de check-in"),
    checkOut: z.string().min(1, "Selecciona la fecha de check-out"),
    adultos: z.coerce.number().int().min(1, "Mínimo 1 adulto").max(13),
    ninos: z.coerce.number().int().min(0).max(12),
    seccion: z.enum(["casa-completa", "seccion-1", "seccion-2"]),
    mensaje: z.string().max(500).optional(),
  })
  .refine(
    (data) => {
      if (!data.checkIn || !data.checkOut) return true;
      return data.checkOut > data.checkIn;
    },
    { message: "El check-out debe ser posterior al check-in", path: ["checkOut"] }
  )
  .refine(
    (data) => data.adultos + data.ninos <= 13,
    {
      message: "La capacidad máxima de la casa es 13 personas",
      path: ["adultos"],
    }
  )
  .transform((data) => ({
    ...data,
    noches: nightsBetween(data.checkIn, data.checkOut),
  }));

export type ReservationForm = z.infer<typeof reservationSchema>;

export type ReservationInput = z.input<typeof reservationSchema>;

import { motion, type Variants } from "framer-motion";
import type { ReactNode } from "react";

const variants: Variants = {
  hidden: { opacity: 0, y: 32 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
  },
};

type FadeInProps = {
  children: ReactNode;
  className?: string;
  delay?: number;
  as?: "div" | "section" | "article";
};

export function FadeIn({
  children,
  className,
  delay = 0,
  as = "motion",
}: FadeInProps) {
  const Component = motion[as === "motion" ? "div" : as];

  return (
    <Component
      className={className}
      variants={variants}
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true, margin: "-60px" }}
      transition={{ delay }}
    >
      {children}
    </Component>
  );
}

export function StaggerContainer({
  children,
  className,
}: {
  children: ReactNode;
  className?: string;
}) {
  return (
    <motion.div
      className={className}
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true, margin: "-40px" }}
      variants={{
        hidden: {},
        visible: { transition: { staggerChildren: 0.1 } },
      }}
    >
      {children}
    </motion.div>
  );
}

export function StaggerItem({
  children,
  className,
}: {
  children: ReactNode;
  className?: string;
}) {
  return (
    <motion.div className={className} variants={variants}>
      {children}
    </motion.div>
  );
}

import { motion } from "framer-motion";
import type { ReactNode } from "react";

export function PageTransition({ children }: { children: ReactNode }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -8 }}
      transition={{ duration: 0.45, ease: [0.22, 1, 0.36, 1] }}
    >
      {children}
    </motion.div>
  );
}

