          </p>
          <div className="virtual-tour__thumbs" role="tablist" aria-label="Espacios">
            {TOUR_SCENES.map((s) => (
              <button
                key={s.id}
                type="button"
                role="tab"
                aria-selected={s.id === sceneId}
                className={`virtual-tour__thumb${s.id === sceneId ? " virtual-tour__thumb--active" : ""}`}
                onClick={() => goToScene(s.id)}
