            {SHOP_CATEGORIES.map((c) => (
              <button
                key={c.id}
                type="button"
                role="tab"
                aria-selected={category === c.id}
                className={`shop-tab${category === c.id ? " shop-tab--active" : ""}`}
                onClick={() => setCategory(c.id)}
              >
                {c.label}
              </button>
            ))}
          </div>

          <AnimatePresence mode="wait">
            <motion.div
              key={category}
              className="shop-grid"
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -8 }}
              transition={{ duration: 0.32, ease: [0.22, 1, 0.36, 1] }}
            >
              {filtered.map((product, i) => {
                const inCart = qtyInCart(product.id);
                const justAdded = addedId === product.id;

                return (
                  <motion.article
                    key={product.id}
                    className="shop-card"
                    initial={{ opacity: 0, y: 16 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.04, duration: 0.4 }}
                    whileHover={{ y: -4 }}
                  >
                    {product.popular && (
                      <span className="shop-card__badge">Popular</span>
                    )}
                    <motion
                      className="shop-card__img"
                      style={{ backgroundImage: `url(${product.image})` }}
                    />
                    <div className="shop-card__body">
                      <span className="shop-card__price">
                        {formatCOP(product.price)}
                      </span>
                      <h3>{product.name}</h3>
                      <p>{product.description}</p>
                      <span className="shop-card__unit">{product.unit}</span>

                      <button
                        type="button"
                        className={`shop-card__btn${justAdded ? " shop-card__btn--done" : ""}`}
                        onClick={() => handleAdd(product.id)}
                      >
                        {justAdded ? (
                          <>
                            <Check size={18} /> Agregado
                          </>
                        ) : (
                          <>
                            <Plus size={18} />
                            {inCart > 0 ? `En carrito (${inCart})` : "Agregar"}
                          </>
                        )}
                      </button>
                    </div>
                  </motion.article>
                );
              })}
            </motion.div>
          </AnimatePresence>

          <FadeIn className="shop-footer-cta">
            <ShoppingBag size={22} />
            <p>Revisa tu carrito desde el icono del menú superior.</p>
          </FadeIn>
        </div>
      </section>
    </>
  );
}

import { useEffect, useLayoutEffect, useRef, useState } from "react";
import { useLocation, useOutlet } from "react-router-dom";
import { AnimatePresence, motion } from "framer-motion";
import { Header } from "./Header";
import { Footer } from "./Footer";
import { WhatsAppFloat } from "./WhatsAppFloat";
import { CartDrawer } from "./CartDrawer";
import { JsonLd } from "./JsonLd";
import { usePageSEO } from "../hooks/usePageSEO";
import { getRouteIndex, pageVariants } from "../lib/pageTransitions";

export function Layout() {
  const location = useLocation();
  const outlet = useOutlet();
  usePageSEO();

  const prevIndex = useRef(getRouteIndex(location.pathname));
  const [direction, setDirection] = useState(0);

  useLayoutEffect(() => {
    const nextIndex = getRouteIndex(location.pathname);
    setDirection(nextIndex >= prevIndex.current ? 1 : -1);
    prevIndex.current = nextIndex;
  }, [location.pathname]);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "instant" in window ? "instant" : "auto" });
  }, [location.pathname]);

  return (
    <>
      <JsonLd />
      <Header />
      <main className="main-content">
        <AnimatePresence mode="wait" custom={direction} initial={false}>
          <motion.div
            key={location.pathname}
            className="page-shell"
            custom={direction}
            variants={pageVariants}
            initial="initial"
            animate="animate"
            exit="exit"
          >
            {outlet}
          </motion.div>
        </AnimatePresence>
      </main>
      <Footer />
      <WhatsAppFloat />
      <CartDrawer />
    </>
  );
}

