}

.header__cart-btn:hover {
  border-color: var(--color-sea-deep);
  background: var(--color-sea-soft);
}

.header__cart-badge {
  position: absolute;
  top: -4px;
  right: -4px;
  min-width: 18px;
  height: 18px;
  padding: 0 4px;
  font-size: 0.65rem;
  font-weight: 700;
  line-height: 18px;
  text-align: center;
  background: var(--color-sea-deep);
  color: var(--color-white);
  border-radius: 999px;
  border: 1px solid var(--color-black);
}

.header__mobile-cart {
  display: flex;
