.section-cta-link {
  text-align: center;
  margin-top: 2.5rem;
}

.section-cta-link--row {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 1.5rem 2.5rem;
}

.header__menu-btn {
  display: flex;
}

@media (min-width: 1100px) {
  .header__actions {
    display: flex;
  }

  .header__menu-btn {
    display: none;
  }
}

@media (max-width: 1099px) {
  .header__actions {
    display: flex;
    margin-left: auto;
    margin-right: 0.5rem;
  }

  .header__actions .header__cta {
    display: none;
  }
}

.header__actions {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-left: auto;
}

.header__cta {
  display: none;
  padding: 0.65rem 1.25rem;
  font-size: 0.72rem;
}

@media (min-width: 900px) {
  .header__nav {
    display: flex;
  }

  .header__cta {
    display: inline-flex;
  }

  .header__menu-btn,
  .header__mobile {
    display: none;
  }
}

